import "../styles/Perfil.css"
import { useNavigate } from "react-router-dom"
import { useState, useEffect, useCallback } from "react"
import axios from "axios"
import jsPDF from "jspdf"
import autoTable from "jspdf-autotable"
import Header from "../components/Header"
import { Mail, GraduationCap, Car, Star, MapPin, Leaf, FileText, FileSpreadsheet, ShieldCheck } from "lucide-react"

const API_BASE_URL = "http://192.168.1.13:3000"; // Recomenda-se migrar para .env futuramente

// Componente auxiliar para animar os números de 0 até o valor final
const AnimatedStat = ({ value, isFloat }) => {
  const [count, setCount] = useState(0);

  useEffect(() => {
    if (value === "Novo" || value === undefined || value === null) {
      setCount(value);
      return;
    }

    const target = parseFloat(value);
    if (isNaN(target)) {
      setCount(value);
      return;
    }

    let startTimestamp = null;
    const duration = 1500; // Duração da animação (1.5 segundos)

    const step = (timestamp) => {
      if (!startTimestamp) startTimestamp = timestamp;
      const progress = Math.min((timestamp - startTimestamp) / duration, 1);
      // Efeito de desaceleração cúbica (ease-out)
      const easeOut = 1 - Math.pow(1 - progress, 3);
      const currentCount = easeOut * target;

      setCount(isFloat ? currentCount.toFixed(1) : Math.floor(currentCount));

      if (progress < 1) {
        window.requestAnimationFrame(step);
      } else {
        setCount(isFloat ? target.toFixed(1) : target);
      }
    };

    window.requestAnimationFrame(step);
  }, [value, isFloat]);

  return <span>{count}</span>;
};

function Perfil() {
  const navigate = useNavigate()
  const [usuario, setUsuario] = useState(null)
  const [isEditing, setIsEditing] = useState(false)
  const [editNome, setEditNome] = useState("")
  const [editMatricula, setEditMatricula] = useState("")
  const [estatisticas, setEstatisticas] = useState(null)

  const carregarEstatisticas = useCallback(async (userId) => {
    try {
      const response = await axios.get(`${API_BASE_URL}/api/auth/estatisticas/${userId}`)
      setEstatisticas(response.data)
    } catch (error) {
      console.error("Erro ao carregar estatísticas:", error)
    }
  }, [])

  useEffect(() => {
    // Puxa os dados do usuário que foram salvos durante o Login
    const userStorage = localStorage.getItem("usuario")
    if (userStorage) {
      const parsedUser = JSON.parse(userStorage)
      setUsuario(parsedUser)
      setEditNome(parsedUser.nome)
      setEditMatricula(parsedUser.matricula)
      carregarEstatisticas(parsedUser.id)
    } else {
      // Se não estiver logado, redireciona para a tela de login
      navigate("/")
    }
  }, [navigate, carregarEstatisticas])

  async function salvarPerfil() {
    if (!editNome || !editMatricula) {
      alert("Nome e matrícula não podem ficar vazios.")
      return
    }

    try {
      const response = await axios.put(`${API_BASE_URL}/api/auth/perfil/${usuario.id}`, {
        nome: editNome,
        matricula: editMatricula
      })

      const usuarioAtualizado = response.data.user
      
      setUsuario(usuarioAtualizado)
      localStorage.setItem("usuario", JSON.stringify(usuarioAtualizado))
      
      setIsEditing(false)
      alert("Perfil atualizado com sucesso!")
    } catch (error) {
      console.error("Erro ao salvar perfil:", error)
      alert("Erro ao atualizar o perfil. Verifique se o servidor está rodando.")
    }
  }

  async function baixarRelatorioCSV() {
    try {
      const response = await axios.get(`${API_BASE_URL}/api/auth/relatorio`)
      const dados = response.data
      
      let csvContent = "data:text/csv;charset=utf-8,"
      csvContent += "Nome,Matrícula,E-mail,Avaliação Média,Total de Avaliações,CO2 Poupado,Valor Sugerido\n"
      
      dados.forEach(row => {
        const nome = row.nome ? String(row.nome).replace(/"/g, '""') : "";
        const matricula = row.matricula ? String(row.matricula).replace(/"/g, '""') : "";
        const email = row.email ? String(row.email).replace(/"/g, '""') : "";
        csvContent += `"${nome}","${matricula}","${email}","${row.media_avaliacao}","${row.total_avaliacoes}","${row.co2_poupado}","${row.valor_sugerido}"\n`
      })

      const encodedUri = encodeURI(csvContent)
      const link = document.createElement("a")
      link.setAttribute("href", encodedUri)
      link.setAttribute("download", "Relatorio_Bigu_Rural.csv")
      document.body.appendChild(link)
      link.click()
      document.body.removeChild(link)
    } catch (error) {
      console.error("Erro ao gerar CSV:", error)
      alert("Erro ao gerar CSV.")
    }
  }

  async function baixarRelatorioPDF() {
    try {
      const response = await axios.get(`${API_BASE_URL}/api/auth/relatorio`)
      const dados = response.data

      const doc = new jsPDF()

      // Exemplo de imagem em Base64 (Quadrado Verde). 
      // Converta a logo real do Bigu Rural em um site como https://www.base64-image.de/ e cole aqui:
      const logoBase64 = "data:image/png;base64,";
      
      // Adiciona a imagem no PDF: addImage(imagem, formato, eixoX, eixoY, largura, altura)
      doc.addImage(logoBase64, 'PNG', 14, 10, 15, 15);

      // Ajustamos a posição do título para ficar ao lado da logo
      doc.text("Relatório de Confiabilidade - Bigu Rural", 35, 20)

      const colunas = ["Nome", "Matrícula", "E-mail", "Avaliação", "Total Avaliações", "CO2 Poupado", "Valor Sugerido"]
      const linhas = dados.map(row => [
        row.nome, row.matricula, row.email, row.media_avaliacao, row.total_avaliacoes, row.co2_poupado, row.valor_sugerido
      ])

      autoTable(doc, {
        head: [colunas],
        body: linhas,
        startY: 35, // Empurramos a tabela um pouco para baixo para não sobrepor a logo
        headStyles: {
          fillColor: '#27ae60', // Verde do tema
          textColor: '#ffffff', // Texto branco
          fontStyle: 'bold'
        }
      })

      doc.save("Relatorio_Bigu_Rural.pdf")
    } catch (error) {
      console.error("Erro detalhado do PDF:", error)
      alert("Erro ao gerar PDF.")
    }
  }

  if (!usuario) {
    return <div style={{ textAlign: 'center', marginTop: '50px', fontSize: '20px' }}>Carregando perfil...</div>
  }

  return (
    <div style={{ display: 'flex', flexDirection: 'column', minHeight: '100vh' }}>
      <Header />

      <div className="perfil-container" style={{ flex: 1 }}>

      <div className="perfil-card">

        <img 
          src={`https://ui-avatars.com/api/?name=${encodeURIComponent(usuario.nome)}&background=27ae60&color=fff&size=120&bold=true`} 
          alt="Foto de Perfil" 
          className="perfil-avatar" 
        />

        {isEditing ? (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '10px', alignItems: 'center', marginBottom: '15px' }}>
            <input 
              type="text" 
              value={editNome} 
              onChange={(e) => setEditNome(e.target.value)} 
              style={{ padding: '10px', fontSize: '18px', borderRadius: '8px', border: '1px solid #ccc', width: '80%', textAlign: 'center' }}
            />
            <input 
              type="text" 
              value={editMatricula} 
              onChange={(e) => setEditMatricula(e.target.value)} 
              style={{ padding: '10px', fontSize: '18px', borderRadius: '8px', border: '1px solid #ccc', width: '80%', textAlign: 'center' }}
            />
          </div>
        ) : (
          <>
            <h1 className="perfil-nome">
              {usuario.nome}
            </h1>
            <p className="perfil-info">
              <span className="icon-animated"><Mail size={22} style={{ verticalAlign: 'middle' }} /></span> {usuario.email}
            </p>
            <p className="perfil-info">
              <span className="icon-animated" style={{ animationDelay: "0.2s" }}><GraduationCap size={22} style={{ verticalAlign: 'middle' }} /></span> Matrícula: {usuario.matricula}
            </p>
          </>
        )}

        <p className="perfil-info">
          <span className="icon-animated" style={{ animationDelay: "0.4s" }}><Car size={22} style={{ verticalAlign: 'middle' }} /></span> Perfil Ativo
        </p>

        {estatisticas && (
          <>
            <p className="perfil-info">
              <span className="icon-animated" style={{ animationDelay: "0.6s" }}><Star size={22} style={{ verticalAlign: 'middle' }} /></span> Avaliação: {estatisticas.media === "Novo" ? "Novo Usuário" : <><AnimatedStat value={estatisticas.media} isFloat={true} /> / 5.0 (<AnimatedStat value={estatisticas.totalAvaliacoes} isFloat={false} /> avaliações)</>}
            </p>
            
            <p className="perfil-info">
              <span className="icon-animated" style={{ animationDelay: "0.8s" }}><MapPin size={22} style={{ verticalAlign: 'middle' }} /></span> Viagens Publicadas: <AnimatedStat value={estatisticas.viagensPublicadas} isFloat={false} />
            </p>

            <p className="perfil-info">
              <span className="icon-animated" style={{ animationDelay: "1.0s" }}><Leaf size={22} style={{ verticalAlign: 'middle' }} /></span> CO2 Poupado: <AnimatedStat value={estatisticas.co2Poupado} isFloat={true} /> kg
            </p>
          </>
        )}

        {isEditing ? (
          <div style={{ display: 'flex', gap: '10px', justifyContent: 'center' }}>
            <button className="perfil-button" onClick={salvarPerfil} style={{ backgroundColor: '#27ae60' }}>
              Salvar
            </button>
            <button className="perfil-button" onClick={() => {setIsEditing(false); setEditNome(usuario.nome); setEditMatricula(usuario.matricula);}} style={{ backgroundColor: '#95a5a6' }}>
              Cancelar
            </button>
          </div>
        ) : (
          <button className="perfil-button" onClick={() => setIsEditing(true)}>
            Editar Perfil
          </button>
        )}

        {/* Área Administrativa para gerar relatórios */}
        <div style={{ marginTop: '40px', paddingTop: '20px', borderTop: '1px solid #ccc' }}>
          <h3 style={{ color: '#555', marginBottom: '15px' }}>📊 Área Administrativa (Relatórios)</h3>
          <div style={{ display: 'flex', gap: '10px', justifyContent: 'center' }}>
            <button className="btn-relatorio" onClick={baixarRelatorioPDF} style={{ backgroundColor: '#e74c3c', color: 'white', border: 'none', padding: '10px 15px', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold', display: 'flex', alignItems: 'center', gap: '6px' }}><FileText size={18} /> Baixar PDF</button>
            <button className="btn-relatorio" onClick={baixarRelatorioCSV} style={{ backgroundColor: '#27ae60', color: 'white', border: 'none', padding: '10px 15px', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold', display: 'flex', alignItems: 'center', gap: '6px' }}><FileSpreadsheet size={18} /> Baixar CSV</button>
            <button className="btn-relatorio" onClick={() => navigate("/admin")} style={{ backgroundColor: '#34495e', color: 'white', border: 'none', padding: '10px 15px', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold', display: 'flex', alignItems: 'center', gap: '6px' }}><ShieldCheck size={18} /> Painel Admin</button>
          </div>
          <p style={{ fontSize: '12px', color: '#888', marginTop: '10px' }}>*Gera estatísticas de confiabilidade de todos os motoristas.</p>
        </div>

      </div>
      </div>

    </div>
  )
}

export default Perfil